        // Add products and their prices
        processor.addProduct("Laptop", 1200);
        processor.addProduct("Smartphone", 800);

        // Process an order
        String orderString = "Laptop–1";
        int totalPrice = processor.calculateTotalPrice(orderString);
        System.out.println("Total Price: $" + totalPrice);
    }
}
